import React from 'react';
import {
  motion,
  useMotionTemplate,
  useMotionValue,
  useReducedMotion,
  useScroll,
  useSpring,
  useTransform,
  Variants,
} from 'framer-motion';

type VibeCardProps = {
  title: string;
  subtitle: string;
  imageSrc: string;
  onClick: () => void;
};

const VibeCard: React.FC<VibeCardProps> = ({
  title,
  subtitle,
  imageSrc,
  onClick,
}) => {
  const reduceMotion = useReducedMotion();
  const cardRef = React.useRef<HTMLDivElement>(null);

  const rotateXInput = useMotionValue(0);
  const rotateYInput = useMotionValue(0);

  const rotateX = useSpring(rotateXInput, { stiffness: 240, damping: 28, mass: 0.8 });
  const rotateY = useSpring(rotateYInput, { stiffness: 240, damping: 28, mass: 0.8 });

  const { scrollYProgress } = useScroll({
    target: cardRef,
    offset: ['start end', 'end start'],
  });

  const imageY = useTransform(scrollYProgress, [0, 1], reduceMotion ? [0, 0] : [-14, 14]);
  const cardY = useTransform(scrollYProgress, [0, 1], reduceMotion ? [0, 0] : [8, -8]);

  const glowOpacity = useTransform(scrollYProgress, [0, 0.5, 1], [0.25, 0.45, 0.3]);
  const glowBackground = useMotionTemplate`radial-gradient(110% 85% at 20% 15%, rgba(16,185,129,${glowOpacity}), transparent 55%), radial-gradient(90% 75% at 85% 20%, rgba(244,211,122,${glowOpacity}), transparent 60%)`;

  const onMouseMove = (event: React.MouseEvent<HTMLDivElement>) => {
    if (reduceMotion) return;

    const bounds = event.currentTarget.getBoundingClientRect();
    const x = event.clientX - bounds.left;
    const y = event.clientY - bounds.top;
    const centerX = bounds.width / 2;
    const centerY = bounds.height / 2;
    const maxTilt = 8;

    rotateYInput.set(((x - centerX) / centerX) * maxTilt);
    rotateXInput.set((-(y - centerY) / centerY) * maxTilt);
  };

  const resetTilt = () => {
    rotateXInput.set(0);
    rotateYInput.set(0);
  };

  const cardVariants: Variants = {
    hidden: reduceMotion ? { opacity: 0 } : { opacity: 0, y: 18 },
    show: {
      opacity: 1,
      y: 0,
      transition: {
        duration: reduceMotion ? 0.2 : 0.55,
        ease: [0.22, 1, 0.36, 1],
      },
    },
  };

  return (
    <motion.div
      ref={cardRef}
      variants={cardVariants}
      style={{
        rotateX: reduceMotion ? 0 : rotateX,
        rotateY: reduceMotion ? 0 : rotateY,
        y: cardY,
        transformStyle: 'preserve-3d',
      }}
      whileHover={reduceMotion ? {} : { scale: 1.02 }}
      transition={{ duration: 0.24, ease: 'easeOut' }}
      className="group relative h-[420px] min-w-0 w-full overflow-hidden rounded-[28px] border border-white/15 bg-panel/85 shadow-[0_14px_36px_rgba(2,8,23,0.42)]"
      onMouseMove={onMouseMove}
      onMouseLeave={resetTilt}
      onFocus={resetTilt}
    >
      <button
        onClick={onClick}
        className="relative block h-full w-full text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-emerald/70"
        aria-label={title}
      >
        <motion.div
          aria-hidden
          className="pointer-events-none absolute inset-0"
          style={{ backgroundImage: glowBackground }}
        />

        <motion.img
          src={imageSrc}
          alt={title}
          style={{ y: imageY }}
          className="absolute inset-0 h-full w-full object-cover"
          animate={reduceMotion ? { scale: 1 } : { scale: 1.02 }}
          whileHover={reduceMotion ? {} : { scale: 1.05 }}
          transition={{ duration: 0.7, ease: [0.22, 1, 0.36, 1] }}
        />

        <div className="pointer-events-none absolute inset-0 bg-gradient-to-b from-black/0 via-black/15 to-black/75" />
        <div className="pointer-events-none absolute inset-0 bg-[linear-gradient(to_right,rgba(148,163,184,0.08)_1px,transparent_1px),linear-gradient(to_bottom,rgba(148,163,184,0.06)_1px,transparent_1px)] bg-[size:36px_36px] opacity-15" />

        <div className="absolute bottom-0 left-0 right-0 p-6">
          <p className="mb-2 text-[10px] font-black uppercase tracking-[0.32em] text-gold/95">
            {subtitle}
          </p>
          <h4 className="font-serif text-[2.1rem] leading-tight text-white">
            {title}
          </h4>
        </div>
      </button>
    </motion.div>
  );
};

export default VibeCard;
